// Time:  O(n) ~ O(2^n)
// Space: O(1) ~ O(2^n)

class Solution {
public:
    int maxLength(vector<string>& arr) {
        vector<int> dp(1);
        for (const auto& x : arr) {
            const auto& x_set = bitset(x);
            if (!x_set) {
                continue;
            }
            const auto curr_size = dp.size();
            for (int i = 0; i < curr_size; ++i) {
                if (dp[i] & x_set) {
                    continue;
                }
                dp.emplace_back(dp[i] | x_set);
            }
        }
        return number_of_one(*max_element(dp.cbegin(), dp.cend(),
                                          [&](const auto& lhs, const auto& rhs) {
                                              return number_of_one(lhs) < number_of_one(rhs);
                                          }));
    }

private:
    int bitset(const string& s) {
        int result = 0;
        for (const auto& c : s) {
            if (result & (1 << (c - 'a'))) {
                return 0;
            }
            result |= 1 << (c - 'a');
        }
        return result;
    }

    int number_of_one(int n) {
    	int count = 0;
        for (; n; n &= n - 1) {
            ++count;
        }
        return count;
    }
};

// Time:  O(2^n)
// Space: O(1)
class Solution2 {
public:
    int maxLength(vector<string>& arr) {
        vector<int> bitsets;
        for (const auto& x : arr) {
            bitsets.emplace_back(bitset(x));
        }
        int result = 0;
        for (int i = 0; i < (1 << arr.size()); ++i) {
            bool skip = false;
            int curr_bitset = 0, curr_len = 0;
            for (int j = 0; j < arr.size(); ++j) {
                if (!(i & (1 << j))) {
                    continue;
                }
                if (!bitsets[j] || (curr_bitset & bitsets[j])) {
                    skip = true;
                    break;
                }
                curr_bitset |= bitsets[j];
                curr_len += arr[j].length();
            }
            if (skip) {
                continue;
            }
            result = max(result, curr_len);
        }
        return result;
    }

private:
    int bitset(const string& s) {
        int result = 0;
        for (const auto& c : s) {
            if (result & (1 << (c - 'a'))) {
                return 0;
            }
            result |= 1 << (c - 'a');
        }
        return result;
    }
};

# Time:  O(n) ~ O(2^n)
# Space: O(1) ~ O(2^n)

power = [1]
log2 = {1:0}
for i in xrange(1, 26):
    power.append(power[-1]<<1)
    log2[power[i]] = i


class Solution(object):
    def maxLength(self, arr):
        """
        :type arr: List[str]
        :rtype: int
        """
        def bitset(s):
            result = 0
            for c in s:
                if result & power[ord(c)-ord('a')]:
                    return 0
                result |= power[ord(c)-ord('a')]
            return result

        def number_of_one(n):
            result = 0
            while n:
                n &= n-1
                result += 1
            return result

        dp = [0]
        for x in arr:
            x_set = bitset(x)
            if not x_set:
                continue
            curr_len = len(dp)
            for i in xrange(curr_len):
                if dp[i] & x_set:
                    continue
                dp.append(dp[i] | x_set)
        return max(number_of_one(s_set) for s_set in dp)


# Time:  O(2^n)
# Space: O(1)
class Solution2(object):
    def maxLength(self, arr):
        """
        :type arr: List[str]
        :rtype: int
        """ 
        def bitset(s):
            result = 0
            for c in s:
                if result & power[ord(c)-ord('a')]:
                    return 0
                result |= power[ord(c)-ord('a')]
            return result

        bitsets = [bitset(x) for x in arr]
        result = 0
        for i in xrange(power[len(arr)]):
            curr_bitset, curr_len = 0, 0
            while i:
                j = i & -i  # rightmost bit
                i ^= j
                j = log2[j]  # log2(j)
                if not bitsets[j] or (curr_bitset & bitsets[j]):
                    break
                curr_bitset |= bitsets[j]
                curr_len += len(arr[j])
            else:
                result = max(result, curr_len)
        return result
